":"2024-02-21T06:36:47.924106Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"my_list <- list(name=\"John\", age=25, scores=c(90, 85, 92), status=TRUE)\nmy_list","metadata":{"execution":{"iopub.status.busy":"2024-02-29T03:57:01.909979Z","iopub.execute_input":"2024-02-29T03:57:01.916739Z","iopub.status.idle":"2024-02-29T03:57:02.01553Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"# we can put list in the list\nemployees <- list(\n  finance = list(\"John\", \"Doe\", \"Jane\"),\n  marketing = list(\"Sarah\", \"Alex\"),\n  development = list(\"James\", \"Maria\", \"Elena\")\n)\n\nemployees","metadata":{"execution":{"iopub.status.busy":"2024-02-29T03:57:44.808287Z","iopub.execute_input":"2024-02-29T03:57:44.810481Z","iopub.status.idle":"2024-02-29T03:57:44.847065Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"markdown","source":"## Chapter_4. Vector","metadata":{}},{"cell_type":"markdown","source":"* 벡터안의 원소는 다 같은 자료형이어야한다!\n* `c(1:10)`:연속적인 숫자를 만들수 있다 -> c(1:10:2) 이런 느낌으론 안됨!\n* `seq(start, end, (by, length.out))`:이걸 이용해서 만듦!","metadata":{}},{"cell_type":"code","source":"c(1:10) # 1 ~ 10 \nc(\"We\", \"Love\", \"R\")\nc(TRUE, FALSE, TRUE)\n\n# seq\nodd <- seq(1, 10, 2)\nodd\neven <- seq(2, 10, 2)\neven\nnum <- c(odd, even)\nnum\n\nseq(1, 10, length.out = 5) # 1~10-> 5개로 쪼개기\nseq(-1, 1, length.out = 5)","metadata":{"execution":{"iopub.status.busy":"2024-02-29T03:51:17.057966Z","iopub.execute_input":"2024-02-29T03:51:17.060202Z","iopub.status.idle":"2024-02-29T03:51:17.143441Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"rep(1, times = 3)\nrep(c(1, 2, 3), times = 3) # the whole vector is repeated 3 times\nrep(c(1, 2, 3), each = 3) # !each! element is repeated 3 times\nrep(c(1, 2, 3), times = c(1, 2, 3)) # element - wise \nrep(c(1, 2, 3), length.out = 8) # element is repeated but length limit is 8","metadata":{"execution":{"iopub.statu