sted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"x <- c(0, 25, 50, 75, 100)\ny <- c(50, 50, 50, 50, 50)\nx > y # elements wise comparison! -> so the result will be boolean (F, F, F, T, T)","metadata":{"execution":{"iopub.status.busy":"2024-02-29T16:04:23.807928Z","iopub.execute_input":"2024-02-29T16:04:23.814782Z","iopub.status.idle":"2024-02-29T16:04:24.052265Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"# Count number of elemnts bigger than 50\nx > 50\n\n# FALSE == 0, TRUE == 1\nsum(x > 50)","metadata":{"execution":{"iopub.status.busy":"2024-02-29T16:04:26.912567Z","iopub.execute_input":"2024-02-29T16:04:26.955347Z","iopub.status.idle":"2024-02-29T16:04:26.984193Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"markdown","source":"`paste(vector, ...)`: concatenate vectors (recycling rule also applies here)","metadata":{}},{"cell_type":"code","source":"fruit <- c(\"APPLE\", \"BANANA\", \"STRWBERRY\")\nfood <- c(\"PIE\", \"JUICE\", \"CAKE\")\n\na<-paste(fruit, food)","metadata":{"execution":{"iopub.status.busy":"2024-03-02T04:19:46.404488Z","iopub.execute_input":"2024-03-02T04:19:46.40928Z","iopub.status.idle":"2024-03-02T04:19:46.443147Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"markdown","source":"`print(\"과일 = \", fruit) ` : `print()` function prints `only one!!! object!!` but in is code we want to print `과일=`, `fruit` ","metadata":{}},{"cell_type":"code","source":"print(paste(\"과일 = \", fruit))","metadata":{"execution":{"iopub.status.busy":"2024-03-02T04:19:35.825261Z","iopub.execute_input":"2024-03-02T04:19:35.828467Z","iopub.status.idle":"2024-03-02T04:19:35.84848Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"print(paste(\"음식 = \", a))","metadata":{"execution":{"iopub.status.busy":"2024-03-02T04:20:09.076063Z","iopub.execute_input":"2024-03-02T04:20:09.078401Z","iopub.status.idle":"2024-03-02T04:20:09.097515Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"cat(\"과일 =\", paste(fruit, collapse=\", \"))","metadata":{"execution":{"iopub.status.busy":"2024-02-29T04:19:32.386181Z","iopub.execute_input":"2024-02-29T04:19:32.38858Z","iopub.status.idle":"2024-02-29T04:19:32.441921Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"markdown","source":"## Chapter_6. Vector_function","metadata":{}},{"cell_type":"code","source":"# absolute value\nabs(-3:5)\nabs(-12)\n\n# logarithm\nlog(10) # natural logarithm\nlog(1:5)\nlog(1:5, base = exp(2)) # e^2\nlog(1:5, base = 2)\n\n# exp\nexp(2)\nexp(2: 5)\n\n#quiz \nquiz<-exp(1:5)\nlog(quiz)","metadata":{"execution":{"iopub.status.busy":"2024-03-02T04:20:37.193742Z","iopub.execute_input":"2024-03-02T04:20:37.195807Z","iopub.status.idle":"2024-03-02T04:20:37.271153Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"factorial(3)\nfactorial(c(1,2,3,4))\nfactorial(seq(1,5,2)) #1, 3, 5\nchoose(5,2) # 5C2 ","metadata":{"execution":{"iopub.status.busy":"2024-03-02T04:23:08.713777Z","iopub.execute_input":"2024-03-02T04:23:08.715713Z","iopub.status.idle":"2024-03-02T04:23:08.760283Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"sqrt(1:5)\n\nsignif(456.789, digits = 2)\nsignif(456.789, digits = 3) # round to specified number of significant digits\n\nround(456.789, digits = 1) # round to specifiied number of decimal places\nround(456.789, digits = 2)\n\nis.infinite(10^(305:310)) # decide if a number is inifnite","metadata":{"execution":{"iopub.status.busy":"2024-03-02T04:27:16.333033Z","iopub.execute_input":"2024-03-02T04:27:16.335009Z","iopub.status.idle":"2024-03-02T04:27:16.390085Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"# simple statistic\n\n# select random numbers\ndata <- round(runif(100, min = 0, max = 100 ), digits = 0)","metadata":{"execution":{"iopub.status.busy":"2024-03-02T04:31:22.350163Z","iopub.execute_input":"2024-03-02T04:31:22.352177Z","iopub.status.idle":"2024-03-02T04:31:22.367593Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"sum(data)\nprod(data)\nmax(data)\nmin(data)\nmean(data)\nmedian(data)\nrange(data)\nsd(data)\nvar(data)","metadata":{"execution":{"iopub.status.busy":"2024-03-02T04:32:08.87685Z","iopub.execute_input":"2024-03-02T04:32:08.882199Z","iopub.status.idle":"2024-03-02T04:32:08.981473Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"# when we have NA\ndata <- c(1, 2, 3, 4, 5, NA)\nsum(data) \nvar(data) # if we dont remove the miss data, all cul result wii be NA\n\n# remove the NA\nsum(data , na.rm = TRUE)\nmean(data, na.rm = TRUE)","metadata":{"execution":{"iopub.status.busy":"2024-03-02T04:35:00.589756Z","iopub.execute_input":"2024-03-02T04:35:00.592787Z","iopub.status.idle":"2024-03-02T04:35:00.648875Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"# EX\ntraffic_death <- c(842, 751, 844, 851, 702)\ncumsum(traffic_death) # cumulative sum\ncumprod(traffic_death)\n\ndiff(traffic_death) # 뒤 - 앞\ndiff(c(1:5))\ndiff(c(1:5), lag = 2) # lag == gap","metadata":{"execution":{"iopub.status.busy":"2024-03-02T04:38:15.053639Z","iopub.execute_input":"2024-03-02T04:38:15.055382Z","iopub.status.idle":"2024-03-02T04:38:15.100443Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"p <- 1:10\nq <- 6:15\ncat(\"합집합:\", union(p,q), \"\\n\") # print(paste(\"합집합 :\", toString(union(p, q))))\ncat(\"교집합:\", intersect(p,q), \"\\n\")\ncat(\"차집합:\", setdiff(p,q), \"\\n\")\ncat(\"차집합:\", setdiff(q,p), \"\\n\")\ncat(\"Equal?:\", setequal(p,q), \"\\n\")","metadata":{"execution":{"iopub.status.busy":"2024-03-02T04:46:53.571201Z","iopub.execute_input":"2024-03-02T04:46:53.574322Z","iopub.status.idle":"2024-03-02T04:46:53.635992Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"is.element(setdiff(p,q), p) # p < setdiff(p,q)\nis.element(setdiff(p,q), q) # p > setdiff(p,q)","metadata":{"execution":{"iopub.status.busy":"2024-03-02T04:48:09.352188Z","iopub.execute_input":"2024-03-02T04:48:09.354675Z","iopub.status.idle":"2024-03-02T04:48:09.385776Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"markdown","source":"## Chapter_7. Vector_indexing","metadata":{}},{"cell_type":"markdown","source":"* Index is position of an elements in a vector(dataframe..)\n* In R, index starts from `1`","metadata":{}},{"cell_type":"code","source":"prime <- c(2, 3, 5, 7, 11, 13 ,17 ,19)\nprime[1]\nprime[2]\nprime[c(1,2,5)] # we can indexing using vector\nprime[seq(1,5, by = 2)]\n\nprime[-1] # negative index removes the element at that index\nprime[-(1:2)]\nprime[-c(1,3,5,7)]\n\n# remove end num\nlength(prime)\nprime[-length(prime)]\nprime[1:length(prime) - 1]","metadata":{"execution":{"iopub.status.busy":"2024-03-02T05:01:06.321124Z","iopub.execute_input":"2024-03-02T05:01:06.327137Z","iopub.status.idle":"2024-03-02T05:01:06.509361Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"# replacement\nnum <- c(2,3,5,7,9,11,13)\nnum[1] <- 3\nnum\n\nnum[c(3,4)] <- c(6,8)\nnum","metadata":{"execution":{"iopub.status.busy":"2024-03-02T05:03:17.871279Z","iopub.execute_input":"2024-03-02T05:03:17.874464Z","iopub.status.idle":"2024-03-02T05:03:17.928885Z"},"trusted":true},"execution_count":null,"outputs":[]},{"cell_type":"code","source":"prime <- c(2, 3, 5, 7, 11, 13, 17, 19)\nprime < 10\nprime[prime < 10] # indexing with boolean\nprime[prime %% 2 == 0]","metadata":{"execution":{"iopub.status.busy":"2024-03-02T07:12:20.832334Z","iopub.execute_input":"2024-03-02T07:12:20.835435Z","iopub.status.idle":"2024-03-02T07:12:20.885224Z"},"trusted":true},"execution_count":120,"outputs":[{"output_type":"display_data","data":{"text/html":"<style>\n.list-inline {list-style: none; margin:0; padding: 0}\n.list